7	#include <utility>
8	#include <rime/candidate.h>
9	#include <rime/common.h>
10	#include <rime/composition.h>
11	#include <rime/config.h>
12	#include <rime/context.h>
13	#include <rime/engine.h>
14	#include <rime/key_event.h>
15	#include <rime/key_table.h>
16	#include <rime/menu.h>
17	#include <rime/schema.h>
18	#include <rime/gear/speller.h>
19	
20	static const char kRimeAlphabet[] = "zyxwvutsrqponmlkjihgfedcba";
21	
22	namespace rime {
23	
24	static inline bool belongs_to(char ch, const string& charset) {
25	  return charset.find(ch) != string::npos;
26	}
27	
28	static bool reached_max_code_length(const an<Candidate>& cand,
29	                                    int max_code_length) {
30	  if (!cand)
31	    return false;
32	  int code_length = static_cast<int>(cand->end() - cand->start());
33	  return code_length >= max_code_length;
34	}
35	
36	static inline bool is_table_entry(const an<Candidate>& cand) {
37	  const auto& type = Candidate::GetGenuineCandidate(cand)->type();
38	  return type == "table" || type == "user_table";
39	}
40	
41	static inline bool is_simple_candidate(const an<Candidate>& cand) {
42	  auto genuine = Candidate::GetGenuineCandidate(cand);
43	  return bool(As<SimpleCandidate>(genuine));
44	}
45	
46	static bool is_auto_selectable(const an<Candidate>& cand,
47	                               const string& input,
48	                               const string& delimiters) {
49	  return
50	      // reaches end of input
51	      cand->end() == input.length() &&
52	      (is_table_entry(cand) || is_simple_candidate(cand)) &&
53	      // no delimiters
54	      input.find_first_of(delimiters, cand->start()) == string::npos;
55	}
56	
57	static bool expecting_an_initial(Context* ctx,
58	                                 const string& alphabet,
59	                                 const string& finals) {
60	  size_t caret_pos = ctx->caret_pos();
61	  if (caret_pos == 0 ||
62	      caret_pos == ctx->composition().GetCurrentStartPosition()) {
63	    return true;
64	  }
65	  const string& input(ctx->input());
66	  char previous_char = input[caret_pos - 1];
67	  return belongs_to(previous_char, finals) ||
68	         !belongs_to(previous_char, alphabet);
69	}
70	
71	Speller::Speller(const Ticket& ticket)
72	    : Processor(ticket), alphabet_(kRimeAlphabet) {
73	  if (Config* config = engine_->schema()->config()) {
74	    config->GetString("speller/alphabet", &alphabet_);
75	    config->GetString("speller/delimiter", &delimiters_);
76	    config->GetString("speller/initials", &initials_);
77	    config->GetString("speller/finals", &finals_);
78	    config->GetInt("speller/max_code_length", &max_code_length_);
79	    config->GetBool("speller/auto_select", &auto_select_);
80	    config->GetBool("speller/use_space", &use_space_);
81	    string pattern;
82	    if (config->GetString("speller/auto_select_pattern", &pattern)) {
83	      auto_select_pattern_ = pattern;
84	    }
85	    string auto_clear;
86	    if (config->GetString("speller/auto_clear", &auto_clear)) {
87	      if (auto_clear == "auto")
88	        auto_clear_ = kClearAuto;
89	      else if (auto_clear == "manual")
90	        auto_clear_ = kClearManual;
91	      else if (auto_clear == "max_length")
92	        auto_clear_ = kClearMaxLength;
93	    }
94	  }
95	  if (initials_.empty()) {
96	    initials_ = alphabet_;
97	  }
98	}
99	
100	ProcessResult Speller::ProcessKeyEvent(const KeyEvent& key_event) {
101	  if (key_event.release() || key_event.ctrl() || key_event.alt() ||
102	      key_event.super())
103	    return kNoop;
104	  int ch = key_event.keycode();
105	  if (ch < 0x20 || ch >= 0x7f)  // not a valid key for spelling
106	    return kNoop;
107	  if (ch == XK_space && (!use_space_ || key_event.shift()))
108	    return kNoop;
109	  if (!belongs_to(ch, alphabet_) && !belongs_to(ch, delimiters_))
110	    return kNoop;
111	  Context* ctx = engine_->context();
112	  bool is_initial = belongs_to(ch, initials_);
113	  if (!is_initial && expecting_an_initial(ctx, alphabet_, finals_)) {
114	    return kNoop;
115	  }
116	  // handles input beyond max_code_length when auto_select is false.
117	  if (is_initial && AutoSelectAtMaxCodeLength(ctx)) {
118	    DLOG(INFO) << "auto-select at max code length.";
119	  } else if ((auto_clear_ == kClearMaxLength || auto_clear_ == kClearManual) &&
120	             AutoClear(ctx)) {
121	    DLOG(INFO) << "auto-clear at max code when no candidate.";
122	  }
123	  // make a backup of previous conversion before modifying input
124	  Segment previous_segment;
125	  if (auto_select_ && ctx->HasMenu()) {
126	    previous_segment = ctx->composition().back();
127	  }
128	  DLOG(INFO) << "add to input: '" << (char)ch << "', " << key_event.repr();
129	  ctx->PushInput(ch);
130	  ctx->BeginEditing();
131	  if (AutoSelectPreviousMatch(ctx, &previous_segment)) {
132	    DLOG(INFO) << "auto-select previous match.";
133	    // after auto-selecting, if only the current non-initial key is left,
134	    // then it should be handled by other processors.
135	    if (!is_initial && ctx->composition().GetCurrentSegmentLength() == 1) {
136	      ctx->PopInput(1);
137	      return kNoop;
138	    }
139	  }
140	  if (AutoSelectUniqueCandidate(ctx)) {
141	    DLOG(INFO) << "auto-select unique candidate.";
142	  } else if (auto_clear_ == kClearAuto && AutoClear(ctx)) {
143	    DLOG(INFO) << "auto-clear when no candidate.";
144	  }
145	  return kAccepted;
146	}
147	
148	bool Speller::AutoSelectAtMaxCodeLength(Context* ctx) {
149	  if (max_code_length_ <= 0)
150	    return false;
151	  if (!ctx->HasMenu())
152	    return false;
153	  auto cand = ctx->GetSelectedCandidate();
154	  if (cand && reached_max_code_length(cand, max_code_length_) &&
155	      is_auto_selectable(cand, ctx->input(), delimiters_)) {
156	    ctx->ConfirmCurrentSelection();
157	    return true;
158	  }
159	  return false;
160	}
161	
162	bool Speller::AutoSelectUniqueCandidate(Context* ctx) {
163	  if (!auto_select_)
164	    return false;
165	  if (!ctx->HasMenu())
166	    return false;
167	  const Segment& seg(ctx->composition().back());
168	  bool unique_candidate = seg.menu->Prepare(2) == 1;
169	  if (!unique_candidate)
170	    return false;
171	  const string& input(ctx->input());
172	  auto cand = seg.GetSelectedCandidate();
173	  bool matches_input_pattern = false;
174	  if (auto_select_pattern_.empty()) {
175	    matches_input_pattern =
176	        max_code_length_ == 0 ||  // match any length if not set
177	        reached_max_code_length(cand, max_code_length_);
178	  } else {
179	    string code(input.substr(cand->start(), cand->end()));
180	    matches_input_pattern = boost::regex_match(code, auto_select_pattern_);
181	  }
182	  if (matches_input_pattern && is_auto_selectable(cand, input, delimiters_)) {
183	    ctx->ConfirmCurrentSelection();
184	    return true;
185	  }
186	  return false;
187	}
188	
189	bool Speller::AutoSelectPreviousMatch(Context* ctx, Segment* previous_segment) {
190	  if (!auto_select_)
191	    return false;
192	  if (max_code_length_ > 0 || !auto_select_pattern_.empty())
193	    return false;
194	  if (ctx->HasMenu())  // if and only if current conversion fails
195	    return false;
196	  if (!previous_segment->menu)
197	    return false;
198	  size_t start = previous_segment->start;
199	  size_t end = previous_segment->end;
200	  string input = ctx->input();
201	  string converted = input.substr(0, end);
202	  if (is_auto_selectable(previous_segment->GetSelectedCandidate(), converted,
203	                         delimiters_)) {
204	    // reuse previous match
205	    ctx->composition().pop_back();
206	    ctx->composition().push_back(std::move(*previous_segment));
207	    ctx->ConfirmCurrentSelection();
208	    if (ctx->get_option("_auto_commit")) {
209	      ctx->set_input(converted);
210	      ctx->Commit();
211	      string rest = input.substr(end);
212	      ctx->set_input(rest);
213	    }
214	    return true;
215	  }
216	  return FindEarlierMatch(ctx, start, end);
217	}
218	
219	bool Speller::AutoClear(Context* ctx) {
220	  if (!ctx->HasMenu() && auto_clear_ > kClearNone &&
221	      (auto_clear_ != kClearMaxLength || max_code_length_ == 0 ||
222	       ctx->input().length() >= (size_t)max_code_length_)) {
223	    ctx->Clear();
224	    return true;
225	  }
226	  return false;
227	}
228	
229	bool Speller::FindEarlierMatch(Context* ctx, size_t start, size_t end) {
230	  if (end <= start + 1)
231	    return false;
232	  string input = ctx->input();
233	  string converted = input;
234	  while (--end > start) {
235	    converted.resize(end);
236	    ctx->set_input(converted);
237	    if (!ctx->HasMenu())
238	      break;
239	    const Segment& segment(ctx->composition().back());
240	    if (is_auto_selectable(segment.GetSelectedCandidate(), converted,
241	                           delimiters_)) {
242	      // select previous match
243	      if (ctx->get_option("_auto_commit")) {
244	        ctx->Commit();
245	        string rest = input.substr(end);
246	        ctx->set_input(rest);
247	        end = 0;
248	      } else {
249	        ctx->ConfirmCurrentSelection();
250	        ctx->set_input(input);
251	      }
252	      if (!ctx->HasMenu()) {
253	        size_t next_start = ctx->composition().GetCurrentStartPosition();
254	        size_t next_end = ctx->composition().GetCurrentEndPosition();
255	        if (next_start == end) {
256	          // continue splitting
257	          FindEarlierMatch(ctx, next_start, next_end);
258	        }
259	      }
260	      return true;
261	    }
262	  }
263	  ctx->set_input(input);
264	  return false;
265	}
266	
267	}  // namespace rime
