15	
16	namespace rime {
17	
18	static struct AsciiModeSwitchStyleDefinition {
19	  const char* repr;
20	  AsciiModeSwitchStyle style;
21	} ascii_mode_switch_styles[] = {{"inline_ascii", kAsciiModeSwitchInline},
22	                                {"commit_text", kAsciiModeSwitchCommitText},
23	                                {"commit_code", kAsciiModeSwitchCommitCode},
24	                                {"clear", kAsciiModeSwitchClear},
25	                                {"set_ascii_mode", kAsciiModeSet},
26	                                {"unset_ascii_mode", kAsciiModeUnset},
27	                                {NULL, kAsciiModeSwitchNoop}};
28	
29	static void load_bindings(const an<ConfigMap>& src,
30	                          AsciiModeSwitchKeyBindings* dest) {
31	  if (!src)
32	    return;
33	  for (auto it = src->begin(); it != src->end(); ++it) {
34	    auto value = As<ConfigValue>(it->second);
35	    if (!value)
36	      continue;
37	    auto* p = ascii_mode_switch_styles;
38	    while (p->repr && p->repr != value->str())
39	      ++p;
40	    if (p->style == kAsciiModeSwitchNoop)
41	      continue;
42	    KeyEvent ke;
43	    if (!ke.Parse(it->first) || ke.modifier() != 0) {
44	      LOG(WARNING) << "invalid ascii mode switch key: " << it->first;
45	      continue;
46	    }
47	    // save binding
48	    (*dest)[ke.keycode()] = p->style;
49	  }
50	}
51	
52	AsciiComposer::AsciiComposer(const Ticket& ticket) : Processor(ticket) {
53	  LoadConfig(ticket.schema);
54	}
55	
56	AsciiComposer::~AsciiComposer() {
57	  connection_.disconnect();
58	}
59	
60	ProcessResult AsciiComposer::ProcessKeyEvent(const KeyEvent& key_event) {
61	  if (key_event.shift() + key_event.ctrl() + key_event.alt() +
62	          key_event.super() >
63	      1) {
64	    shift_key_pressed_ = ctrl_key_pressed_ = alt_key_pressed_ =
65	        super_key_pressed_ = false;
66	    return kNoop;
67	  }
68	  if (caps_lock_switch_style_ != kAsciiModeSwitchNoop) {
69	    ProcessResult result = ProcessCapsLock(key_event);
70	    if (result != kNoop)
71	      return result;
72	  }
73	  int ch = key_event.keycode();
74	  if (ch == XK_Eisu_toggle) {  // Alphanumeric toggle
75	    if (!key_event.release()) {
76	      shift_key_pressed_ = ctrl_key_pressed_ = false;
77	      ToggleAsciiModeWithKey(ch);
78	      return kAccepted;
79	    } else {
80	      return kRejected;
81	    }
82	  }
83	  bool is_shift = (ch == XK_Shift_L || ch == XK_Shift_R);
84	  bool is_ctrl = (ch == XK_Control_L || ch == XK_Control_R);
85	  bool is_alt = (ch == XK_Alt_L || ch == XK_Alt_R);
86	  bool is_super = (ch == XK_Super_L || ch == XK_Super_R);
87	  if (is_shift || is_ctrl || is_alt || is_super) {
88	    if (key_event.release()) {
89	      if (shift_key_pressed_ || ctrl_key_pressed_ || alt_key_pressed_ ||
90	          super_key_pressed_) {
91	        auto now = std::chrono::steady_clock::now();
92	        if (((is_shift && shift_key_pressed_) ||
93	             (is_ctrl && ctrl_key_pressed_) || (is_alt && alt_key_pressed_) ||
94	             (is_super && super_key_pressed_)) &&
95	            now < toggle_expired_) {
96	          ToggleAsciiModeWithKey(ch);
97	        }
98	        shift_key_pressed_ = ctrl_key_pressed_ = alt_key_pressed_ =
99	            super_key_pressed_ = false;
100	        return kNoop;
101	      }
102	    } else if (!(shift_key_pressed_ || ctrl_key_pressed_ || alt_key_pressed_ ||
103	                 super_key_pressed_)) {
104	      // first key down
105	      if (is_shift)
106	        shift_key_pressed_ = true;
107	      else if (is_ctrl)
108	        ctrl_key_pressed_ = true;
109	      else if (is_alt)
110	        alt_key_pressed_ = true;
111	      else if (is_super)
112	        super_key_pressed_ = true;
113	      // will not toggle unless the toggle key is released shortly
114	      const auto toggle_duration_limit = std::chrono::milliseconds(500);
115	      auto now = std::chrono::steady_clock::now();
116	      toggle_expired_ = now + toggle_duration_limit;
117	    }
118	    return kNoop;
119	  }
120	  // other keys
121	  shift_key_pressed_ = ctrl_key_pressed_ = alt_key_pressed_ =
122	      super_key_pressed_ = false;
123	  // possible key binding: Control+x, Shift+space
124	  if (key_event.ctrl() || key_event.alt() || key_event.super() ||
125	      (key_event.shift() && ch == XK_space)) {
126	    return kNoop;
127	  }
128	  Context* ctx = engine_->context();
129	  bool ascii_mode = ctx->get_option("ascii_mode");
130	  if (ascii_mode) {
131	    if (!ctx->IsComposing()) {
132	      return kRejected;  // direct commit
133	    }
134	    // edit inline ascii string
135	    if (!key_event.release() && ch >= 0x20 && ch < 0x80) {
136	      ctx->PushInput(ch);
137	      return kAccepted;
138	    }
139	  }
140	  return kNoop;
141	}
142	
143	ProcessResult AsciiComposer::ProcessCapsLock(const KeyEvent& key_event) {
144	  int ch = key_event.keycode();
145	  if (ch == XK_Caps_Lock) {
146	    if (!key_event.release()) {
147	      shift_key_pressed_ = ctrl_key_pressed_ = alt_key_pressed_ =
148	          super_key_pressed_ = false;
149	      // temporarily disable good-old (uppercase) Caps Lock as mode switch key
150	      // in case the user switched to ascii mode with other keys, eg. with Shift
151	      if (good_old_caps_lock_ && !toggle_with_caps_) {
152	        Context* ctx = engine_->context();
153	        bool ascii_mode = ctx->get_option("ascii_mode");
154	        if (ascii_mode) {
155	          return kRejected;
156	        }
157	      }
158	      toggle_with_caps_ = !key_event.caps();
159	      // NOTE: for Linux, Caps Lock modifier is clear when we are about to
160	      // turn it on; for Windows it is the opposite:
161	      // Caps Lock modifier has been set before we process VK_CAPITAL.
162	      // here we assume IBus' behavior and invert caps with ! operation.
163	      SwitchAsciiMode(!key_event.caps(), caps_lock_switch_style_);
164	      // When good_old_caps_lock is enabled, allow the key event to pass
165	      // through the input method to toggle the Caps Lock state.
166	      return good_old_caps_lock_ ? kRejected : kAccepted;
167	    } else {
168	      return kRejected;
169	    }
170	  }
171	  if (key_event.caps()) {
172	    if (!good_old_caps_lock_ && !key_event.release() && !key_event.ctrl() &&
173	        !key_event.alt() && !key_event.super() && isascii(ch) && isalpha(ch)) {
174	      // output ascii characters ignoring Caps Lock
175	      if (islower(ch))
176	        ch = toupper(ch);
177	      else if (isupper(ch))
178	        ch = tolower(ch);
179	      engine_->CommitText(string(1, ch));
180	      return kAccepted;
181	    } else {
182	      return kRejected;
183	    }
184	  }
185	  return kNoop;
186	}
