188	void AsciiComposer::LoadConfig(Schema* schema) {
189	  bindings_.clear();
190	  caps_lock_switch_style_ = kAsciiModeSwitchNoop;
191	  good_old_caps_lock_ = false;
192	  if (!schema)
193	    return;
194	  Config* config = schema->config();
195	  the<Config> preset_config(Config::Require("config")->Create("default"));
196	  if (!config->GetBool("ascii_composer/good_old_caps_lock",
197	                       &good_old_caps_lock_)) {
198	    if (preset_config) {
199	      preset_config->GetBool("ascii_composer/good_old_caps_lock",
200	                             &good_old_caps_lock_);
201	    }
202	  }
203	  if (auto bindings = config->GetMap("ascii_composer/switch_key")) {
204	    load_bindings(bindings, &bindings_);
205	  } else if (auto bindings = preset_config ? preset_config->GetMap(
206	                                                 "ascii_composer/switch_key")
207	                                           : nullptr) {
208	    load_bindings(bindings, &bindings_);
209	  } else {
210	    LOG(ERROR) << "Missing ascii bindings.";
211	    return;
212	  }
213	  auto it = bindings_.find(XK_Caps_Lock);
214	  if (it != bindings_.end()) {
215	    caps_lock_switch_style_ = it->second;
216	    if (caps_lock_switch_style_ == kAsciiModeSwitchInline ||
217	        caps_lock_switch_style_ == kAsciiModeSet ||
218	        caps_lock_switch_style_ == kAsciiModeUnset) {
219	      // can't do that
220	      caps_lock_switch_style_ = kAsciiModeSwitchClear;
221	    }
222	  }
223	}
224	
225	bool AsciiComposer::ToggleAsciiModeWithKey(int key_code) {
226	  auto it = bindings_.find(key_code);
227	  if (it == bindings_.end())
228	    return false;
229	  AsciiModeSwitchStyle style = it->second;
230	  Context* ctx = engine_->context();
231	  bool old_mode = ctx->get_option("ascii_mode");
232	  bool new_mode = (style == kAsciiModeSet)     ? true
233	                  : (style == kAsciiModeUnset) ? false
234	                                               : !old_mode;
235	  if (old_mode == new_mode) {
236	    return false;
237	  }
238	  SwitchAsciiMode(new_mode, style);
239	  toggle_with_caps_ = (key_code == XK_Caps_Lock);
240	  return true;
241	}
242	
243	void AsciiComposer::SwitchAsciiMode(bool ascii_mode,
244	                                    AsciiModeSwitchStyle style) {
245	  DLOG(INFO) << "ascii mode: " << ascii_mode << ", switch style: " << style;
246	  Context* ctx = engine_->context();
247	  if (ctx->IsComposing()) {
248	    connection_.disconnect();
249	    // temporary ascii mode in desired manner
250	    if (style == kAsciiModeSwitchInline) {
251	      LOG(INFO) << "converting current composition to "
252	                << (ascii_mode ? "ascii" : "non-ascii") << " mode.";
253	      if (ascii_mode) {
254	        connection_ = ctx->update_notifier().connect(
255	            [this](Context* ctx) { OnContextUpdate(ctx); });
256	      }
257	    } else if (style == kAsciiModeSwitchCommitText) {
258	      ctx->ConfirmCurrentSelection();
259	    } else if (style == kAsciiModeSwitchCommitCode) {
260	      ctx->ClearNonConfirmedComposition();
261	      ctx->Commit();
262	    } else if (style == kAsciiModeSwitchClear || style == kAsciiModeSet ||
263	               style == kAsciiModeUnset) {
264	      ctx->Clear();
265	    }
266	  }
267	  // refresh non-confirmed composition with new mode
268	  ctx->set_option("ascii_mode", ascii_mode);
269	}
270	
271	void AsciiComposer::OnContextUpdate(Context* ctx) {
272	  if (!ctx->IsComposing()) {
273	    connection_.disconnect();
274	    // quit temporary ascii mode
275	    ctx->set_option("ascii_mode", false);
276	  }
277	}
