108	inline static bool is_vertical_text(Context* ctx) {
109	  return ctx->get_option("_vertical");
110	}
111	
112	inline static bool is_linear_layout(Context* ctx) {
113	  return ctx->get_option("_linear") ||
114	         // Deprecated. equivalent to {_linear: true, _vertical: false}
115	         ctx->get_option("_horizontal");
116	}
117	
118	ProcessResult Selector::ProcessKeyEvent(const KeyEvent& key_event) {
119	  if (key_event.release() || key_event.alt() || key_event.super())
120	    return kNoop;
121	  Context* ctx = engine_->context();
122	  if (ctx->composition().empty())
123	    return kNoop;
124	  Segment& current_segment(ctx->composition().back());
125	  if (!current_segment.menu || current_segment.HasTag("raw"))
126	    return kNoop;
127	
128	  TextOrientation text_orientation =
129	      is_vertical_text(ctx) ? Vertical : Horizontal;
130	  CandidateListLayout candidate_list_layout =
131	      is_linear_layout(ctx) ? Linear : Stacked;
132	  auto result = KeyBindingProcessor::ProcessKeyEvent(
133	      key_event, ctx, text_orientation | candidate_list_layout,
134	      FallbackOptions::None);
135	  if (result != kNoop) {
136	    return result;
137	  }
138	
139	  int ch = key_event.keycode();
140	  int index = -1;
141	  const string& select_keys(engine_->schema()->select_keys());
142	  if (!select_keys.empty() && !key_event.ctrl() && ch >= 0x20 && ch < 0x7f) {
143	    size_t pos = select_keys.find((char)ch);
144	    if (pos != string::npos) {
145	      index = static_cast<int>(pos);
146	    }
147	  } else if (ch >= XK_0 && ch <= XK_9)
148	    index = ((ch - XK_0) + 9) % 10;
149	  else if (ch >= XK_KP_0 && ch <= XK_KP_9)
150	    index = ((ch - XK_KP_0) + 9) % 10;
151	  if (index >= 0) {
152	    SelectCandidateAt(ctx, index);
153	    return kAccepted;
154	  }
155	  // not handled
156	  return kNoop;
157	}
158	
159	bool Selector::PreviousPage(Context* ctx) {
160	  Composition& comp = ctx->composition();
161	  if (comp.empty())
162	    return false;
163	  int page_size = engine_->schema()->page_size();
164	  int selected_index = comp.back().selected_index;
165	  int index = selected_index < page_size ? 0 : selected_index - page_size;
166	  ctx->Highlight(index);
167	  comp.back().tags.insert("paging");
168	  return true;
169	}
170	
171	bool Selector::NextPage(Context* ctx) {
172	  Composition& comp = ctx->composition();
173	  if (comp.empty() || !comp.back().menu)
174	    return false;
175	  int page_size = engine_->schema()->page_size();
176	  int index = comp.back().selected_index + page_size;
177	  int page_start = (index / page_size) * page_size;
178	  int candidate_count = comp.back().menu->Prepare(page_start + page_size);
179	  if (candidate_count <= page_start) {
180	    bool page_down_cycle = engine_->schema()->page_down_cycle();
181	    if (page_down_cycle) {  // Cycle back to page 1 if true
182	      index = 0;
183	    } else {
184	      // no-op; consume the key event so that page down is not sent to the app.
185	      return true;
186	    }
187	  } else if (index >= candidate_count) {
188	    index = candidate_count - 1;
189	  }
190	  ctx->Highlight(index);
191	  comp.back().tags.insert("paging");
192	  return true;
193	}
194	
195	inline static bool caret_at_end_of_input(Context* ctx) {
196	  return ctx->caret_pos() >= ctx->input().length();
197	}
198	
199	bool Selector::PreviousCandidate(Context* ctx) {
200	  if (is_linear_layout(ctx) && !caret_at_end_of_input(ctx)) {
201	    // let navigator handle the arrow key.
202	    return false;
203	  }
204	  Composition& comp = ctx->composition();
205	  if (comp.empty())
206	    return false;
207	  int index = comp.back().selected_index;
208	  if (index <= 0) {
209	    // in case of linear layout, fall back to navigator
210	    return !is_linear_layout(ctx);
211	  }
212	  ctx->Highlight(index - 1);
213	  comp.back().tags.insert("paging");
214	  return true;
215	}
216	
217	bool Selector::NextCandidate(Context* ctx) {
218	  if (is_linear_layout(ctx) && !caret_at_end_of_input(ctx)) {
219	    // let navigator handle the arrow key.
220	    return false;
221	  }
222	  Composition& comp = ctx->composition();
223	  if (comp.empty() || !comp.back().menu)
224	    return false;
225	  int index = comp.back().selected_index + 1;
226	  int candidate_count = comp.back().menu->Prepare(index + 1);
227	  if (candidate_count <= index)
228	    return true;
229	  ctx->Highlight(index);
230	  comp.back().tags.insert("paging");
231	  return true;
232	}
233	
234	bool Selector::Home(Context* ctx) {
235	  if (ctx->composition().empty())
236	    return false;
237	  Segment& seg(ctx->composition().back());
238	  if (seg.selected_index > 0) {
239	    ctx->Highlight(0);
240	    return true;
241	  }
242	  // let navigator handle the key event.
243	  return false;
244	}
245	
246	bool Selector::End(Context* ctx) {
247	  if (ctx->caret_pos() < ctx->input().length()) {
248	    // navigator should handle this
249	    return false;
250	  }
251	  // this is cool:
252	  return Home(ctx);
253	}
254	
255	bool Selector::SelectCandidateAt(Context* ctx, int index) {
256	  Composition& comp = ctx->composition();
257	  if (comp.empty())
258	    return false;
259	  int page_size = engine_->schema()->page_size();
260	  if (index >= page_size)
261	    return false;
262	  int selected_index = comp.back().selected_index;
263	  int page_start = (selected_index / page_size) * page_size;
264	  return ctx->Select(page_start + index);
265	}
