130	bool Navigator::Rewind(Context* ctx) {
131	  BeginMove(ctx);
132	  size_t confirmed_pos = ctx->composition().GetConfirmedPosition();
133	  // take a jump leftwards when there are multiple non-confirmed spans,
134	  // but not from the middle of a span.
135	  if (spans_.Count(confirmed_pos, spans_.end()) > 1 &&
136	      spans_.HasVertex(ctx->caret_pos())) {
137	    JumpLeft(ctx, confirmed_pos, true);
138	  } else {
139	    MoveLeft(ctx);
140	  }
141	  return true;
