144	bool Navigator::Forward(Context* ctx) {
145	  BeginMove(ctx);
146	  size_t confirmed_pos = ctx->composition().GetConfirmedPosition();
147	  // when half-selected, count the rest spans.
148	  if (spans_.Count(confirmed_pos, spans_.end()) > 1 &&
149	      spans_.HasVertex(ctx->caret_pos())) {
150	    JumpRight(ctx, confirmed_pos, true);
151	  } else {
152	    MoveRight(ctx);
153	  }
154	  return true;
