194	void Navigator::BeginMove(Context* ctx) {
195	  ctx->BeginEditing();
196	  // update spans
197	  if (input_ != ctx->input() || ctx->caret_pos() > spans_.end()) {
198	    input_ = ctx->input();
199	    spans_.Clear();
200	    for (const auto& seg : ctx->composition()) {
201	      if (auto phrase = As<Phrase>(
202	              Candidate::GetGenuineCandidate(seg.GetSelectedCandidate()))) {
203	        spans_.AddSpans(phrase->spans());
204	      }
205	      spans_.AddSpan(seg.start, seg.end);
206	    }
207	  }
208	}
