210	bool Navigator::JumpLeft(Context* ctx, size_t start_pos, bool loop) {
211	  DLOG(INFO) << "jump left.";
212	  size_t caret_pos = ctx->caret_pos();
213	  size_t end_of_translation = spans_.end();
214	  size_t end_of_input = ctx->input().length();
215	  size_t span_start_pos = ToSpanStart(caret_pos);
216	  size_t new_pos =
217	      // 跳過未翻譯的輸入碼
218	      (span_start_pos > end_of_translation) ? end_of_translation
219	      // 迴轉？
220	      : (loop && span_start_pos <= start_pos)
221	          ?
222	          // 若未翻譯完則須重譯，光標迴轉到結尾
223	          (end_of_input > end_of_translation)
224	              ? end_of_input
225	              // 迴轉後向前找
226	              : (std::max)(start_pos, spans_.PreviousStop(end_of_input))
227	          // 跳至前一個切分點
228	          : (std::max)(start_pos, spans_.PreviousStop(span_start_pos));
229	  if (syllable_jump_position_ == BeforeDelimiter)
230	    new_pos = ToSyllableEnd(new_pos);
231	  if (new_pos != caret_pos) {
232	    ctx->set_caret_pos(new_pos);
233	    return true;
234	  }
235	  return false;
236	}
237	
238	bool Navigator::JumpRight(Context* ctx, size_t start_pos, bool loop) {
239	  DLOG(INFO) << "jump right.";
240	  size_t caret_pos = ctx->caret_pos();
241	  size_t end_of_translation = spans_.end();
242	  size_t end_of_input = ctx->input().length();
243	  size_t span_end_pos = ToSpanEnd(caret_pos);
244	  size_t new_pos =
245	      // 已在結尾則從頭開始向後找
246	      (loop && span_end_pos == end_of_input) ? spans_.NextStop(start_pos)
247	      // 跳過未翻譯的輸入碼
248	      : (span_end_pos >= end_of_translation) ? end_of_input
249	                                             // 跳至後一個切分點
250	                                             : spans_.NextStop(span_end_pos);
251	  if (syllable_jump_position_ == BeforeDelimiter)
252	    new_pos = ToSyllableEnd(new_pos);
253	  if (new_pos != caret_pos) {
254	    ctx->set_caret_pos(new_pos);
255	    return true;
256	  }
257	  return false;
258	}
259	
260	bool Navigator::MoveLeft(Context* ctx) {
261	  DLOG(INFO) << "navigate left.";
262	  size_t caret_pos = ctx->caret_pos();
263	  if (caret_pos == 0)
264	    return false;
265	  ctx->set_caret_pos(caret_pos - 1);
266	  return true;
267	}
268	
269	bool Navigator::MoveRight(Context* ctx) {
270	  DLOG(INFO) << "navigate right.";
271	  size_t caret_pos = ctx->caret_pos();
272	  if (caret_pos >= ctx->input().length())
273	    return false;
274	  ctx->set_caret_pos(caret_pos + 1);
275	  return true;
276	}
277	
278	bool Navigator::GoHome(Context* ctx) {
279	  DLOG(INFO) << "navigate home.";
280	  size_t caret_pos = ctx->caret_pos();
281	  const Composition& comp = ctx->composition();
282	  if (!comp.empty()) {
283	    size_t confirmed_pos = caret_pos;
284	    for (const Segment& seg : boost::adaptors::reverse(comp)) {
285	      if (seg.status >= Segment::kSelected) {
286	        break;
287	      }
288	      confirmed_pos = seg.start;
289	    }
290	    if (confirmed_pos < caret_pos) {
291	      ctx->set_caret_pos(confirmed_pos);
292	      return true;
293	    }
294	  }
295	  if (caret_pos != 0) {
296	    ctx->set_caret_pos(0);
297	    return true;
298	  }
299	  return false;
300	}
301	
302	bool Navigator::GoToEnd(Context* ctx) {
303	  DLOG(INFO) << "navigate end.";
304	  size_t end_pos = ctx->input().length();
305	  if (ctx->caret_pos() != end_pos) {
306	    ctx->set_caret_pos(end_pos);
307	    return true;
308	  }
309	  return false;
310	}
