320	// Spans only consider start and end. To jump precisely, sometimes we
321	// need to fix the current position to a semantic boundary.
322	//
323	// Find 'start' if pos in leading delimiters, i.e. [start, leading_delim_end].
324	size_t Navigator::ToSpanStart(size_t pos) {
