57	                                       Context* ctx,
58	                                       Keymap& keymap) {
59	  auto binding = keymap.find(key_event);
60	  if (binding != keymap.end()) {
61	    auto action = binding->second;
62	    if (RIME_THIS_CALL_AS(T, action)(ctx)) {
63	      DLOG(INFO) << "action key accepted: " << key_event.repr();
64	      return true;
65	    }
66	  }
67	  return false;
68	}
