62	static void radio_select_option(Context* ctx,
63	                                const Switches::SwitchOption& the_option) {
64	  Switches::FindRadioGroupOption(
65	      the_option.the_switch, [ctx, &the_option](Switches::SwitchOption option) {
66	        bool value = (option.option_index == the_option.option_index);
67	        if (ctx->get_option(option.option_name) != value) {
68	          ctx->set_option(option.option_name, value);
69	        }
70	        return Switches::kContinue;
71	      });
72	}
