78	static Switches::SwitchOption switch_by_index(Switches& switches,
79	                                              const string& option) {
80	  try {
81	    size_t index = std::stoul(option.substr(1));
82	    return switches.ByIndex(index);
83	  } catch (...) {
84	  }
85	  return {};
86	}
