89	  if (!engine)
90	    return;
91	  Context* ctx = engine->context();
92	  Switches switches(engine->schema()->config());
93	  auto the_option = is_switch_index(option) ? switch_by_index(switches, option)
94	                                            : switches.OptionByName(option);
95	  if (the_option.found() && the_option.type == Switches::kRadioGroup) {
96	    auto selected_option = switches.FindRadioGroupOption(
97	        the_option.the_switch, [ctx](Switches::SwitchOption option) {
98	          return ctx->get_option(option.option_name) ? Switches::kFound
99	                                                     : Switches::kContinue;
100	        });
101	    if (!selected_option.found()) {
102	      // invalid state: none is selected. select the given option.
103	      radio_select_option(ctx, the_option);
104	      return;
105	    }
106	    // cycle through the ratio group and select the next option.
107	    auto next_option = Switches::Cycle(selected_option);
108	    if (next_option.found()) {
109	      radio_select_option(ctx, next_option);
110	    }
111	  } else {  // toggle
112	    // option can be an index. use the found option name, or an arbitrary
113	    // option name specified by caller.
114	    auto option_name = the_option.found() ? the_option.option_name : option;
115	    ctx->set_option(option_name, !ctx->get_option(option_name));
116	  }
117	}
118	
119	static void set_option(Engine* engine, const string& option) {
120	  if (!engine)
121	    return;
122	  Context* ctx = engine->context();
123	  Switches switches(engine->schema()->config());
124	  auto the_option = switches.OptionByName(option);
125	  if (the_option.found() && the_option.type == Switches::kRadioGroup) {
126	    radio_select_option(ctx, the_option);
127	  } else {
128	    ctx->set_option(option, 1);
129	  }
130	}
131	
132	static void unset_option(Engine* engine, const string& option) {
133	  if (!engine)
134	    return;
135	  Context* ctx = engine->context();
136	  Switches switches(engine->schema()->config());
137	  auto the_option = switches.OptionByName(option);
138	  if (the_option.found() && the_option.type == Switches::kRadioGroup) {
139	    if (ctx->get_option(option)) {
140	      auto default_option = Switches::Reset(the_option);
141	      if (default_option.found()) {
142	        radio_select_option(ctx, default_option);
143	      }
144	    }
145	  } else {
146	    ctx->set_option(option, 0);
147	  }
148	}
