150	static void select_schema(Engine* engine, const string& schema) {
151	  if (!engine)
152	    return;
153	  if (schema == ".next") {
154	    Switcher switcher(engine);
155	    switcher.SelectNextSchema();
156	  } else {
157	    engine->ApplySchema(new Schema(schema));
158	  }
159	}
