161	void KeyBindings::LoadBindings(const an<ConfigList>& bindings) {
162	  if (!bindings)
163	    return;
164	  for (size_t i = 0; i < bindings->size(); ++i) {
165	    auto map = As<ConfigMap>(bindings->GetAt(i));
166	    if (!map)
167	      continue;
168	    auto whence = map->GetValue("when");
169	    if (!whence)
170	      continue;
171	    auto pattern = map->GetValue("accept");
172	    if (!pattern)
173	      continue;
174	    KeyBinding binding;
175	    binding.whence = translate_condition(whence->str());
176	    if (binding.whence == kNever) {
177	      continue;
178	    }
179	    KeyEvent key;
180	    if (!key.Parse(pattern->str())) {
181	      LOG(WARNING) << "invalid key binding #" << i
182	                   << ", with invalid accept pattern: " << pattern->str()
183	                   << ".";
184	      continue;
185	    }
186	    if (auto target = map->GetValue("send")) {
187	      KeyEvent key;
188	      if (key.Parse(target->str())) {
189	        binding.target.push_back(std::move(key));
190	      } else {
191	        LOG(WARNING) << "invalid key binding #" << i
192	                     << ", with invalid send pattern: " << target->str() << ".";
193	        continue;
194	      }
195	    } else if (auto target = map->GetValue("send_sequence")) {
196	      if (!binding.target.Parse(target->str())) {
197	        LOG(WARNING) << "invalid key sequence #" << i
198	                     << ", with invalid send_sequence pattern: "
199	                     << target->str() << ".";
200	        continue;
201	      }
202	    } else if (auto option = map->GetValue("toggle")) {
203	      binding.action = [option](auto engine) {
204	        toggle_option(engine, option->str());
205	      };
206	    } else if (auto option = map->GetValue("set_option")) {
207	      binding.action = [option](auto engine) {
208	        set_option(engine, option->str());
209	      };
210	    } else if (auto option = map->GetValue("unset_option")) {
211	      binding.action = [option](auto engine) {
212	        unset_option(engine, option->str());
213	      };
214	    } else if (auto schema = map->GetValue("select")) {
215	      binding.action = [schema](auto engine) {
216	        select_schema(engine, schema->str());
217	      };
218	    } else {
219	      LOG(WARNING) << "invalid key binding #" << i
220	                   << ", accept: " << pattern->str()
221	                   << ", when: " << whence->str() << ".";
222	      continue;
223	    }
224	    Bind(key, binding);
225	  }
226	}
