228	void KeyBindings::Bind(const KeyEvent& key, const KeyBinding& binding) {
229	  auto& vec = (*this)[key];
230	  // insert before existing binding of the same condition
231	  auto lb = std::lower_bound(vec.begin(), vec.end(), binding);
232	  vec.insert(lb, binding);
