271	ProcessResult KeyBinder::ProcessKeyEvent(const KeyEvent& key_event) {
272	  if (redirecting_ || !key_bindings_ || key_bindings_->empty())
273	    return kNoop;
274	  if (ReinterpretPagingKey(key_event))
275	    return kNoop;
276	  if (key_bindings_->find(key_event) == key_bindings_->end())
277	    return kNoop;
278	  KeyBindingConditions conditions(engine_->context());
279	  for (const KeyBinding& binding : (*key_bindings_)[key_event]) {
280	    if (conditions.find(binding.whence) == conditions.end())
281	      continue;
282	    PerformKeyBinding(binding);
283	    return kAccepted;
284	  }
285	  // not handled
286	  return kNoop;
