309	bool KeyBinder::ReinterpretPagingKey(const KeyEvent& key_event) {
310	  if (key_event.release())
311	    return false;
312	  bool ret = false;
313	  int ch = (key_event.modifier() == 0) ? key_event.keycode() : 0;
314	  // reinterpret period key followed by alphabetic keys
315	  // unless period/comma key has been used multiple times
316	  if (ch == '.' && (last_key_ == '.' || last_key_ == ',')) {
317	    last_key_ = 0;
318	    return ret;
319	  }
320	  if (last_key_ == '.' && ch >= 'a' && ch <= 'z') {
321	    Context* ctx = engine_->context();
322	    const string& input(ctx->input());
323	    if (!input.empty() && input[input.length() - 1] != '.') {
324	      LOG(INFO) << "reinterpreted key: '" << last_key_ << "', successor: '"
325	                << (char)ch << "'";
326	      ctx->PushInput(last_key_);
327	      ret = true;
328	    }
329	  }
330	  last_key_ = ch;
331	  return ret;
332	}
